input.command:
# Validate JSON files
$files = @(
  "C:\Users\yaniv\.claude\settings.json",
  "c:\Users\yaniv\ליו\.claude\settings.json",
  "C:\Users\yaniv\.claude\templates\project\.claude\settings.json",
  "c:\Users\yaniv\ליו\.mcp.json",
  "C:\Users\yaniv\.claude\templates\project\.mcp.json"
)
foreach ($f in $files) {
  try {
    $null = Get-Content $f -Raw | ConvertFrom-Json
    Write-Host "✓ $f"
  } catch {
    Write-Host "✗ $f — $($_.Exception.Message)"
  }
}

# Check symlinks
$links = @(
  "c:\Users\yaniv\ליו\.claude\skills\shannon",
  "c:\Users\yaniv\ליו\.claude\skills\valyu-best-practices"
)
foreach ($l in $links) {
  $item = Get-Item $l -ErrorAction SilentlyContinue
  if ($item -and $item.Attributes -match "ReparsePoint") {
    $target = $item.Target
    $targetExists = Test-Path $target
    if ($targetExists) { Write-Host "✓ $($item.Name) → $target" }
    else { Write-Host "✗ $($item.Name) → $target (TARGET MISSING)" }
  } else {
    Write-Host "✗ $l — not a symlink or missing"
  }
}

