input.command:
# Validate all JSON files
$files = @(
  "C:\Users\yaniv\.claude\settings.json",
  "c:\Users\yaniv\ליו\.claude\settings.json",
  "C:\Users\yaniv\.claude\templates\project\.claude\settings.json",
  "c:\Users\yaniv\ליו\.mcp.json",
  "C:\Users\yaniv\.claude\templates\project\.mcp.json"
)
$ok = $true
foreach ($f in $files) {
  try {
    $null = Get-Content $f -Raw | ConvertFrom-Json
    Write-Host "✓ $(Split-Path $f -Leaf)"
  } catch {
    Write-Host "✗ $f — $($_.Exception.Message)"
    $ok = $false
  }
}

# Verify global MCPs
Write-Host "`n--- MCPs גלובליים ---"
claude mcp list 2>&1 | Select-String "playwright|context7|github"

# Verify no PostToolUse in global
Write-Host "`n--- PostToolUse בגלובלי ---"
$g = Get-Content "C:\Users\yaniv\.claude\settings.json" | ConvertFrom-Json
if ($g.hooks.PostToolUse) { Write-Host "✗ עדיין קיים" } else { Write-Host "✓ הוסר" }

# Verify symlinks
Write-Host "`n--- Symlinks ---"
@("shannon","valyu-best-practices") | ForEach-Object {
  $t = (Get-Item "c:\Users\yaniv\ליו\.claude\skills\$_").Target
  if (Test-Path $t) { Write-Host "✓ $_" } else { Write-Host "✗ $_ → $t (MISSING)" }
}

